// Header.tsx
import React, { useState, useEffect } from 'react';
import { Link } from 'gatsby';
import './header.css'
import PrayerTimes from '../PrayerTimes/PrayerTimes';
import { NewsItem, NavItem, DropdownItem } from '../../contexts/types';
import { useResolved } from '../../ppm/util/ResolvedContentContext';

interface HeaderProps {
  activeNav?: string;
  showHero?: boolean;
}

const Header: React.FC<HeaderProps> = ({ activeNav = 'home', showHero = true }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);
  const [mobileDropdown, setMobileDropdown] = useState<string | null>(null);

  // === THE ONLY REAL CHANGE ===
  const displayData = useResolved();
  // ============================


  const headerData = displayData.pages.home.header;
  const headerContent = displayData.global.headerContent;
  const newsContent = displayData.pages.home.newsContent;
  const supportContent = displayData.pages.home.supportContent;

  // Extract SBU TV data
  const tvSection = supportContent?.columns.find((c: any) => c.id === 'tv');
  const tvLink = tvSection?.items?.[0]?.link || '/videos';

  // Helper to extract first image from HTML body if no explicit thumbnail exists
  const extractFirstImage = (body: string | undefined) => {
    if (!body) return null;
    const imgMatch = body.match(/src=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']/i);
    let imageUrl = imgMatch ? imgMatch[1] : null;

    if (imageUrl) {
      imageUrl = imageUrl.replace(
        /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
        'https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/'
      );
    }
    return imageUrl;
  };

  const featuredNews = newsContent?.items?.find((item: NewsItem) => item.isFeatured);
  const featuredImage = featuredNews?.image || extractFirstImage(featuredNews?.body);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDropdown = (dropdown: string) => {
    setActiveDropdown(activeDropdown === dropdown ? null : dropdown);
  };

  const toggleMobileDropdown = (dropdown: string) => {
    setMobileDropdown(mobileDropdown === dropdown ? null : dropdown);
  };

  const closeMobileMenu = () => {
    setMobileMenuOpen(false);
    setActiveDropdown(null);
    setMobileDropdown(null);
  };

  const titleLines = headerData.title.split('\n').filter((line: string) => line.trim());

  return (
    <>
      <PrayerTimes />
      <header className={`header ${isScrolled || !showHero ? 'scrolled' : ''}`}>
        <div className="header-container">
          <div className="logo-container">
            <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '1rem', textDecoration: 'none' }}>
              <div className="logo-icon">
                <img src={headerContent.logoImage} alt="SBU Logo" />
              </div>
              <div className="logo-text">
                <div className="logo-vietnamese">{headerContent.logoVietnamese}</div>
                <div className="logo-english">{headerContent.logoEnglish}</div>
              </div>
            </Link>
          </div>

          <nav className={`desktop-nav ${mobileMenuOpen ? 'mobile-open' : ''}`}>
            <ul className="nav-list">
              {headerContent.navigationItems.map((navItem: NavItem) => (
                navItem.isDropdown ? (
                  <li
                    key={navItem.id}
                    className={`nav-item dropdown ${activeDropdown === navItem.id ? 'active' : ''}`}
                    onMouseEnter={() => setActiveDropdown(navItem.id)}
                    onMouseLeave={() => setActiveDropdown(null)}
                  >
                    <button
                      className="dropdown-toggle"
                      onClick={() => toggleDropdown(navItem.id)}
                      aria-expanded={activeDropdown === navItem.id}
                    >
                      {navItem.label}
                      <svg className="dropdown-arrow" width="10" height="6" viewBox="0 0 10 6" fill="none">
                        <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                      </svg>
                    </button>
                    {navItem.dropdownItems && (
                      <div className="dropdown-menu">
                        {navItem.dropdownItems.map((dropItem: DropdownItem) => (
                          <div key={dropItem.id} className="dropdown-item-wrapper" style={{ position: 'relative' }}>
                            <Link to={dropItem.href} className={`dropdown-item ${dropItem.subItems ? 'has-subs' : ''}`}>
                              {dropItem.label}
                              {dropItem.subItems && (
                                <svg className="sub-arrow" width="6" height="10" viewBox="0 0 6 10" fill="none" style={{ marginLeft: 'auto' }}>
                                  <path d="M1 1L5 5L1 9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                                </svg>
                              )}
                            </Link>
                            {dropItem.subItems && (
                              <div className="sub-dropdown-menu">
                                {dropItem.subItems.map((sub: any) => (
                                  <Link key={sub.id} to={sub.href} className="dropdown-item sub">
                                    {sub.label}
                                  </Link>
                                ))}
                              </div>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </li>
                ) : (
                  <li key={navItem.id} className={`nav-item ${activeNav === navItem.id ? 'active' : ''}`}>
                    <Link to={navItem.href} className="nav-link">{navItem.label}</Link>
                  </li>
                )
              ))}
            </ul>
          </nav>

          <div className="mobile-controls">
            <button
              className="mobile-menu-toggle"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              aria-label="Toggle menu"
            >
              <span className={`menu-line ${mobileMenuOpen ? 'open' : ''}`}></span>
              <span className={`menu-line ${mobileMenuOpen ? 'open' : ''}`}></span>
              <span className={`menu-line ${mobileMenuOpen ? 'open' : ''}`}></span>
            </button>
          </div>
        </div>
      </header>

      {showHero && headerData.published && (
        <section
          className="hero"
          style={{
            '--desktop-bg': `url('${headerData.backgroundImage}')`,
            '--mobile-bg': `url('${headerData.mobileBackgroundImage || headerData.backgroundImage}')`
          } as React.CSSProperties}
        >
          <div className="hero-overlay"></div>
          <div className="hero-content">
            <h1 className="hero-title">
              <span className="title-desktop">
                {titleLines.map((line: string, index: number) => (
                  <span key={index} className={`title-line-${index + 1}`}>
                    {line}
                  </span>
                ))}
              </span>
              <span className="title-mobile">{headerData.mobileTitle || titleLines[0]}</span>
            </h1>
            {headerData.subtitle && (
              <p className="hero-subtitle">{headerData.subtitle}</p>
            )}

            <div className="mobile-title-box">
              <Link to={tvLink} style={{ display: 'block', width: '100%', height: '100%' }}>
                {featuredNews?.image ? (
                  <img
                    src={featuredNews.image}
                    alt="Featured News"
                    className="mobile-featured-img"
                  />
                ) : (
                  <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#f0f0f0' }}>
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ width: '48px', height: '48px', color: 'var(--color-saffron)', opacity: '0.6' }}>
                      <rect x="2" y="7" width="20" height="15" rx="2" ry="2" />
                      <polyline points="17 2 12 7 7 2" />
                    </svg>
                  </div>
                )}
              </Link>
            </div>
          </div>
        </section>
      )}
      <div className={`mobile-menu-overlay ${mobileMenuOpen ? 'active' : ''}`} onClick={closeMobileMenu}></div>
      <div className={`mobile-menu ${mobileMenuOpen ? 'active' : ''}`}>
        <div className="mobile-menu-header">
          <div className="mobile-logo">
            <div className="logo-icon">
              <img src={headerContent.logoImage} alt="SBU Logo" />
            </div>
            <div className="mobile-logo-text">
              <div>{headerContent.logoVietnamese}</div>
              <div>{headerContent.logoEnglish}</div>
            </div>
          </div>
          <button className="mobile-menu-close" onClick={closeMobileMenu} aria-label="Close menu">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
              <path d="M18 6L6 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
              <path d="M6 6L18 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
        </div>
        <ul className="mobile-nav-list">
          {headerContent.navigationItems.map((navItem: NavItem) => (
            navItem.isDropdown ? (
              <li key={navItem.id} className={`mobile-nav-item mobile-dropdown ${mobileDropdown === navItem.id ? 'active' : ''}`}>
                <button
                  className="mobile-dropdown-toggle"
                  onClick={() => toggleMobileDropdown(navItem.id)}
                  aria-expanded={mobileDropdown === navItem.id}
                >
                  {navItem.label}
                  <svg className="dropdown-arrow" width="10" height="6" viewBox="0 0 10 6" fill="none">
                    <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </button>
                {navItem.dropdownItems && (
                  <div className="mobile-dropdown-menu">
                    {navItem.dropdownItems.map((dropItem: DropdownItem) => (
                      <div key={dropItem.id} className="mobile-sub-wrapper">
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <Link to={dropItem.href} className="mobile-dropdown-item" onClick={closeMobileMenu}>
                            {dropItem.label}
                          </Link>
                          {dropItem.subItems && (
                            <button 
                              className={`mobile-inner-toggle ${mobileDropdown === `inner-${dropItem.id}` ? 'active' : ''}`}
                              onClick={(e) => {
                                e.stopPropagation();
                                setMobileDropdown(mobileDropdown === `inner-${dropItem.id}` ? navItem.id : `inner-${dropItem.id}`);
                              }}
                            >
                              <svg width="10" height="6" viewBox="0 0 10 6" fill="none">
                                <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                              </svg>
                            </button>
                          )}
                        </div>
                        {dropItem.subItems && (
                          <div className={`mobile-inner-menu ${mobileDropdown === `inner-${dropItem.id}` ? 'active' : ''}`}>
                            {dropItem.subItems.map((sub: any) => (
                              <Link key={sub.id} to={sub.href} className="mobile-dropdown-item inner" onClick={closeMobileMenu}>
                                {sub.label}
                              </Link>
                            ))}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </li>
            ) : (
              <li key={navItem.id} className="mobile-nav-item">
                <Link to={navItem.href} className="mobile-nav-link" onClick={closeMobileMenu}>
                  {navItem.label}
                </Link>
              </li>
            )
          ))}
        </ul>
      </div>
    </>
  );
};

export default Header;